import type { BlockData, BlockType, PageTheme } from "@/lib/db/schema";
import { getPresetById, themePresets } from "@/lib/themes";

export type TemplateBlock = {
  type: BlockType;
  data: BlockData;
};

export type PageTemplate = {
  id: string;
  name: string;
  category: string;
  emoji: string;
  description: string;
  themePresetId: string;
  suggestedTitle: string;
  suggestedBio: string;
  blocks: TemplateBlock[];
  featured?: boolean;
  suggestedCoverUrl?: string;
  themeOverride?: Partial<PageTheme>;
};

// ============== HELPERS ==============

const link = (label: string, url: string): TemplateBlock => ({
  type: "link",
  data: { kind: "link", label, url },
});
const text = (content: string): TemplateBlock => ({
  type: "text",
  data: { kind: "text", content, align: "center" },
});
const divider: TemplateBlock = { type: "divider", data: { kind: "divider" } };

